const TRIM_VALS = [-0.7,-0.5,0.0,0.3,1.0];
const M3_TO_GAL = 264.172;
const TANQUES_BARCAZA=["1B","1E","2B","2E","3B","3E","4B","4E","5B","5E"];

function interp(x,x0,x1,y0,y1){if(x1===x0)return y0;return y0+(y1-y0)*(x-x0)/(x1-x0);}

function interpolarBarcaza(tabla,sonda,trimVal,trimDir){
  if(!tabla||tabla.length===0||sonda===null||sonda===undefined||isNaN(sonda))return null;
  const n=tabla.length;
  let ri0=0,ri1=1;
  if(sonda<=tabla[0][0]){ri0=0;ri1=0;}
  else if(sonda>=tabla[n-1][0]){ri0=n-2;ri1=n-1;}
  else{for(let i=0;i<n-1;i++){if(sonda>=tabla[i][0]&&sonda<=tabla[i+1][0]){ri0=i;ri1=i+1;break;}}}
  const s0=tabla[ri0][0],s1=ri0===ri1?tabla[ri0][0]+0.001:tabla[ri1][0];
  const colAt=c=>interp(sonda,s0,s1,tabla[ri0][c],tabla[ri1][c]);
  let tf=trimDir==="PROA"?trimVal:trimDir==="POPA"?-trimVal:0;
  tf=Math.max(TRIM_VALS[0],Math.min(TRIM_VALS[TRIM_VALS.length-1],tf));
  let ci0=0,ci1=1;
  for(let i=0;i<TRIM_VALS.length-1;i++){if(tf>=TRIM_VALS[i]&&tf<=TRIM_VALS[i+1]){ci0=i;ci1=i+1;break;}}
  if(tf<=TRIM_VALS[0]){ci0=0;ci1=0;}
  if(tf>=TRIM_VALS[TRIM_VALS.length-1]){ci0=TRIM_VALS.length-2;ci1=TRIM_VALS.length-1;}
  const t0=TRIM_VALS[ci0],t1=ci0===ci1?TRIM_VALS[ci0]+0.001:TRIM_VALS[ci1];
  return Math.max(0,interp(tf,t0,t1,colAt(ci0+1),colAt(ci1+1)));
}

function interpolarTKT(tabla,sondaMM){
  if(!tabla||sondaMM===null||isNaN(sondaMM))return null;
  const n=tabla.length;
  if(sondaMM<=tabla[0][0])return tabla[0][1];
  if(sondaMM>=tabla[n-1][0])return tabla[n-1][1];
  let lo=0,hi=n-1;
  while(hi-lo>1){const mid=Math.floor((lo+hi)/2);if(tabla[mid][0]<=sondaMM)lo=mid;else hi=mid;}
  return interp(sondaMM,tabla[lo][0],tabla[hi][0],tabla[lo][1],tabla[hi][1]);
}

function calcVCF(api,tempC){
  if(!api||!tempC||isNaN(api)||isNaN(tempC))return null;
  // ASTM Tabla 6B: convertir API a densidad, usar K0/K1
  const rho15=(141.5/(131.5+api))*999.016;
  const alpha=(186.9696+0.486926*rho15)/(rho15*rho15);
  const d=tempC-15.5556; // referencia 60Ã‚Â°F
  return Math.exp(-alpha*d*(1+0.8*alpha*d));
}

function calcF13(api){
  if(!api||api<=0||isNaN(api))return null;
  const lo=Math.floor(api),hi=Math.ceil(api);
  if(lo===hi)return TABLA13[lo]||null;
  if(!TABLA13[lo]||!TABLA13[hi])return TABLA13[lo]||TABLA13[hi]||null;
  return TABLA13[lo]+(api-lo)*(TABLA13[hi]-TABLA13[lo]);
}

// Registro de tablas por barcaza. Agregar QBS003 aqui cuando llegue.
const BARCAZA_TABLES = {
  "QBS002": { TB, TK },
  // "QBS003": { TB: TB_QBS003, TK: TK_QBS003 },
};

// "QBS002-2E" -> { barcaza:"QBS002", tank:"2E" }
// "QBS002-TKT-1" -> { barcaza:"QBS002", tank:"TKT-1" }
export function parseTankId(tankId){
  if(!tankId)return null;
  const s=String(tankId);
  const m=s.match(/^(QBS\d+)-(.+)$/i);
  if(!m)return null;
  return { barcaza:m[1].toUpperCase(), tank:m[2].toUpperCase() };
}

export function calcularGalonesP1(tankId,sondaCm,api,tempC){
  const parsed=parseTankId(tankId);
  if(!parsed)return null;
  const tables=BARCAZA_TABLES[parsed.barcaza];
  if(!tables)return null;
  const isTKT=parsed.tank.startsWith("TKT");
  const tabla=isTKT?tables.TK[parsed.tank]:tables.TB[parsed.tank];
  if(!tabla)return null;
  const m3=isTKT?interpolarTKT(tabla,sondaCm):interpolarBarcaza(tabla,sondaCm,0,"CERO");
  if(m3===null||m3===undefined)return null;
  const galonesB=Math.round(m3*M3_TO_GAL);
  if(!api||!tempC||isNaN(Number(api))||isNaN(Number(tempC)))return galonesB;
  const vcf=calcVCF(Number(api),Number(tempC));
  return vcf?Math.round(galonesB*vcf):galonesB;
}